// Une datos originales + respuesta de IA.
// Si OpenAI falla, aplica fallback por palabras clave para que la demo nunca se caiga.
const input = $('02 Code - Validar y normalizar input').first().json;
const aiRaw = $json;

function fallbackEspecialidad(s) {
  const t = s.toLowerCase();
  if (/(pecho|cardiaco|corazรณn|corazon|palpitaciones|presiรณn alta|presion alta)/.test(t)) return { especialidad: 'Cardiologรญa', urgencia: 'alta', razon: 'Los sรญntomas pueden estar relacionados con el sistema cardiovascular.' };
  if (/(mareo|migraรฑa|migraรฑa|convuls|desmayo|debilidad|adormecimiento|cabeza)/.test(t)) return { especialidad: 'Neurologรญa', urgencia: 'media', razon: 'Los sรญntomas se relacionan con el sistema nervioso.' };
  if (/(estรณmago|estomago|diarrea|vรณmito|vomito|nรกusea|nausea|gastritis|abdomen)/.test(t)) return { especialidad: 'Gastroenterologรญa', urgencia: 'media', razon: 'Los sรญntomas se relacionan con el sistema digestivo.' };
  if (/(tos|respirar|respiraciรณn|respiracion|asma|pulmรณn|pulmon|flema)/.test(t)) return { especialidad: 'Neumologรญa', urgencia: 'media', razon: 'Los sรญntomas se relacionan con vรญas respiratorias.' };
  if (/(fractura|golpe|rodilla|hueso|torcedura|espalda|articulaciรณn|articulacion)/.test(t)) return { especialidad: 'Traumatologรญa', urgencia: 'media', razon: 'Los sรญntomas se relacionan con lesiones musculoesquelรฉticas.' };
  if (/(piel|roncha|picazรณn|picazon|alergia|sarpullido|grano|dermatitis)/.test(t)) return { especialidad: 'Dermatologรญa', urgencia: 'baja', razon: 'Los sรญntomas se relacionan con piel.' };
  if (/(garganta|oรญdo|oido|nariz|sinusitis|amรญgdala|amigdala)/.test(t)) return { especialidad: 'Otorrinolaringologรญa', urgencia: 'baja', razon: 'Los sรญntomas se relacionan con oรญdo, nariz o garganta.' };
  return { especialidad: 'Medicina General', urgencia: 'baja', razon: 'Los sรญntomas requieren una primera valoraciรณn mรฉdica general.' };
}

let clasificacion = null;

try {
  const content = aiRaw.choices?.[0]?.message?.content;
  if (content) clasificacion = JSON.parse(content);
} catch (e) {
  clasificacion = null;
}

if (!clasificacion || !clasificacion.especialidad) {
  clasificacion = fallbackEspecialidad(input.sintoma);
  clasificacion.fuente = 'fallback_reglas';
} else {
  clasificacion.fuente = 'ia_openai';
}

return [{
  json: {
    ...input,
    ia: clasificacion
  }
}];

